import { Component, OnInit } from '@angular/core';
import { TranslateService } from '@ngx-translate/core';
import { CategoryService, Category } from '../../services/category.service';

@Component({
  selector: 'app-settings',
  templateUrl: './settings.component.html',
  styleUrls: ['./settings.component.css']
})
export class SettingsComponent implements OnInit {
  activeTab: 'revenue' | 'expense' | 'investment' = 'revenue';
  categories: Category[] = [];
  filteredCategories: Category[] = [];
  loading = false;
  error: string | null = null;

  // Form state
  showForm = false;
  editMode = false;
  currentCategory: Partial<Category> = {};

  // Parent categories for hierarchical structure
  parentCategories: Category[] = [];

  constructor(
    private categoryService: CategoryService,
    private translate: TranslateService
  ) {}

  ngOnInit(): void {
    this.loadCategories();
  }

  loadCategories(): void {
    this.loading = true;
    this.error = null;

    this.categoryService.getAllCategories().subscribe({
      next: (data) => {
        this.categories = data;
        this.filterCategories();
        this.updateParentCategories();
        this.loading = false;
      },
      error: (error) => {
        this.error = 'Failed to load categories';
        this.loading = false;
        console.error('Error loading categories:', error);
      }
    });
  }

  filterCategories(): void {
    this.filteredCategories = this.categories.filter(
      cat => cat.type === this.activeTab && cat.is_active === 'true'
    );
  }

  updateParentCategories(): void {
    this.parentCategories = this.categories.filter(
      cat => cat.type === this.activeTab && !cat.parent_category && cat.is_active === 'true'
    );
  }

  onTabChange(tab: 'revenue' | 'expense' | 'investment'): void {
    this.activeTab = tab;
    this.filterCategories();
    this.updateParentCategories();
    this.cancelForm();
  }

  openAddForm(): void {
    this.showForm = true;
    this.editMode = false;
    this.currentCategory = {
      type: this.activeTab,
      name_en: '',
      name_ar: '',
      parent_category: '',
      is_active: 'true'
    };
  }

  openEditForm(category: Category): void {
    this.showForm = true;
    this.editMode = true;
    this.currentCategory = { ...category };
  }

  cancelForm(): void {
    this.showForm = false;
    this.editMode = false;
    this.currentCategory = {};
  }

  saveCategory(): void {
    if (!this.currentCategory.name_en || !this.currentCategory.name_ar) {
      alert(this.translate.instant('SETTINGS.VALIDATION.NAME_REQUIRED'));
      return;
    }

    this.loading = true;

    if (this.editMode && this.currentCategory.id) {
      this.categoryService.updateCategory(this.currentCategory.id, this.currentCategory).subscribe({
        next: () => {
          this.loadCategories();
          this.cancelForm();
        },
        error: (error) => {
          this.error = 'Failed to update category';
          this.loading = false;
          console.error('Error updating category:', error);
        }
      });
    } else {
      this.categoryService.createCategory(this.currentCategory).subscribe({
        next: () => {
          this.loadCategories();
          this.cancelForm();
        },
        error: (error) => {
          this.error = 'Failed to create category';
          this.loading = false;
          console.error('Error creating category:', error);
        }
      });
    }
  }

  deleteCategory(category: Category): void {
    if (!confirm(this.translate.instant('SETTINGS.DELETE_CONFIRM', { name: this.getCategoryName(category) }))) {
      return;
    }

    this.loading = true;
    this.categoryService.deleteCategory(category.id).subscribe({
      next: () => {
        this.loadCategories();
      },
      error: (error) => {
        this.error = 'Failed to delete category';
        this.loading = false;
        console.error('Error deleting category:', error);
      }
    });
  }

  getCategoryName(category: Category): string {
    const currentLang = this.translate.currentLang;
    return currentLang === 'ar' ? category.name_ar : category.name_en;
  }

  getParentCategoryName(parentName: string): string {
    if (!parentName) return '';
    const parent = this.categories.find(cat => cat.name_en === parentName);
    return parent ? this.getCategoryName(parent) : parentName;
  }

  getChildCategories(parentCategory: Category): Category[] {
    return this.filteredCategories.filter(
      cat => cat.parent_category === parentCategory.name_en
    );
  }

  isParentCategory(category: Category): boolean {
    return !category.parent_category;
  }
}
<div class="settings-container">
  <div class="header">
    <h1>{{ 'SETTINGS.TITLE' | translate }}</h1>
    <a routerLink="/dashboard" class="btn btn-secondary">{{ 'NAV.DASHBOARD' | translate }}</a>
  </div>

  <div class="settings-content">
    <!-- Tabs -->
    <div class="tabs">
      <button 
        class="tab-button" 
        [class.active]="activeTab === 'revenue'"
        (click)="onTabChange('revenue')">
        {{ 'SETTINGS.REVENUE_CATEGORIES' | translate }}
      </button>
      <button 
        class="tab-button" 
        [class.active]="activeTab === 'expense'"
        (click)="onTabChange('expense')">
        {{ 'SETTINGS.EXPENSE_CATEGORIES' | translate }}
      </button>
      <button 
        class="tab-button" 
        [class.active]="activeTab === 'investment'"
        (click)="onTabChange('investment')">
        {{ 'SETTINGS.INVESTMENT_TYPES' | translate }}
      </button>
    </div>

    <!-- Error Message -->
    <div class="error-message" *ngIf="error">
      {{ error }}
    </div>

    <!-- Loading Indicator -->
    <div class="loading" *ngIf="loading && !showForm">
      {{ 'COMMON.LOADING' | translate }}...
    </div>

    <!-- Tab Content -->
    <div class="tab-content" *ngIf="!loading || showForm">

      <!-- Add Button -->
      <div class="action-bar" *ngIf="!showForm">
        <button class="btn btn-primary" (click)="openAddForm()">
          <span class="icon">+</span>
          {{ 'SETTINGS.ADD_CATEGORY' | translate }}
        </button>
      </div>

      <!-- Category Form -->
      <div class="category-form" *ngIf="showForm">
        <h3>{{ editMode ? ('SETTINGS.EDIT_CATEGORY' | translate) : ('SETTINGS.ADD_CATEGORY' | translate) }}</h3>

        <div class="form-group">
          <label>{{ 'SETTINGS.ENGLISH_NAME' | translate }} *</label>
          <input 
            type="text" 
            [(ngModel)]="currentCategory.name_en" 
            [placeholder]="'SETTINGS.ENGLISH_NAME_PLACEHOLDER' | translate"
            class="form-control">
        </div>

        <div class="form-group">
          <label>{{ 'SETTINGS.ARABIC_NAME' | translate }} *</label>
          <input 
            type="text" 
            [(ngModel)]="currentCategory.name_ar" 
            [placeholder]="'SETTINGS.ARABIC_NAME_PLACEHOLDER' | translate"
            class="form-control"
            dir="rtl">
        </div>

        <div class="form-group" *ngIf="activeTab === 'expense'">
          <label>{{ 'SETTINGS.PARENT_CATEGORY' | translate }}</label>
          <select [(ngModel)]="currentCategory.parent_category" class="form-control">
            <option value="">{{ 'SETTINGS.NO_PARENT' | translate }}</option>
            <option *ngFor="let parent of parentCategories" [value]="parent.name_en">
              {{ getCategoryName(parent) }}
            </option>
          </select>
        </div>

        <div class="form-actions">
          <button class="btn btn-primary" (click)="saveCategory()">
            {{ 'COMMON.SAVE' | translate }}
          </button>
          <button class="btn btn-secondary" (click)="cancelForm()">
            {{ 'COMMON.CANCEL' | translate }}
          </button>
        </div>
      </div>

      <!-- Categories List -->
      <div class="categories-list" *ngIf="!showForm">
        <div class="category-group" *ngFor="let category of filteredCategories">
          <div class="category-item" *ngIf="isParentCategory(category)" [class.parent]="true">
            <div class="category-info">
              <span class="category-name">{{ getCategoryName(category) }}</span>
              <span class="category-badge">{{ 'SETTINGS.PARENT' | translate }}</span>
            </div>
            <div class="category-actions">
              <button class="btn-icon" (click)="openEditForm(category)" [title]="'COMMON.EDIT' | translate">
                ✏️
              </button>
              <button class="btn-icon" (click)="deleteCategory(category)" [title]="'COMMON.DELETE' | translate">
                🗑️
              </button>
            </div>
          </div>

          <!-- Child Categories -->
          <div class="child-categories" *ngIf="isParentCategory(category)">
            <div class="category-item child" *ngFor="let child of getChildCategories(category)">
              <div class="category-info">
                <span class="category-name">{{ getCategoryName(child) }}</span>
              </div>
              <div class="category-actions">
                <button class="btn-icon" (click)="openEditForm(child)" [title]="'COMMON.EDIT' | translate">
                  ✏️
                </button>
                <button class="btn-icon" (click)="deleteCategory(child)" [title]="'COMMON.DELETE' | translate">
                  🗑️
                </button>
              </div>
            </div>
          </div>
        </div>

        <!-- Standalone Categories (no parent) -->
        <div class="category-item standalone" *ngFor="let category of filteredCategories" 
             [hidden]="isParentCategory(category) || category.parent_category">
          <div class="category-info">
            <span class="category-name">{{ getCategoryName(category) }}</span>
          </div>
          <div class="category-actions">
            <button class="btn-icon" (click)="openEditForm(category)" [title]="'COMMON.EDIT' | translate">
              ✏️
            </button>
            <button class="btn-icon" (click)="deleteCategory(category)" [title]="'COMMON.DELETE' | translate">
              🗑️
            </button>
          </div>
        </div>

        <div class="no-data" *ngIf="filteredCategories.length === 0">
          {{ 'SETTINGS.NO_CATEGORIES' | translate }}
        </div>
      </div>
    </div>
  </div>
</div>
